import React, { useEffect, useState } from 'react';
import { Link } from 'react-router-dom';
import api from '../services/api';
import { useAuth } from '../contexts/AuthContext';

function ProductsList() {
  const [products, setProducts] = useState([]);
  const { user } = useAuth();

  useEffect(() => {
    api.get('/products').then(res => setProducts(res.data));
  }, []);

  const handleDelete = async (id) => {
    if (window.confirm('Удалить товар?')) {
      await api.delete(`/products/${id}`);
      setProducts(products.filter(p => p.id !== id));
    }
  };

  return (
    <div>
      <h1>Товары Monster High</h1>
      <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fill, minmax(280px, 1fr))', gap: '1.5rem' }}>
        {products.map(product => (
          <div key={product.id} className="card" style={{ display: 'flex', flexDirection: 'column' }}>
            {product.imageUrl && (
              <img 
                src={product.imageUrl} 
                alt={product.title} 
                style={{ width: '100%', height: '200px', objectFit: 'cover', borderRadius: '8px', marginBottom: '0.5rem' }} 
              />
            )}
            <h3>{product.title}</h3>
            <p>Категория: {product.category}</p>
            <p>Цена: {product.price} ₽</p>
            <div style={{ marginTop: 'auto', display: 'flex', gap: '0.5rem' }}>
              <Link to={`/products/${product.id}`}>Подробнее</Link>
              {(user?.role === 'seller' || user?.role === 'admin') && (
                <Link to={`/products/edit/${product.id}`}>Редактировать</Link>
              )}
              {user?.role === 'admin' && (
                <button className="danger" onClick={() => handleDelete(product.id)}>Удалить</button>
              )}
            </div>
          </div>
        ))}
      </div>
    </div>
  );
}

export default ProductsList;
